ValidationRule.errorConditionFormula:
AND(
    NOT($Setup.RES_Config_Switch__c.RES_Validation_Rules_Off__c),

    /* Apply only for required Record Types */
    OR(
        $RecordType.DeveloperName = "RES_Company",
        $RecordType.DeveloperName = "RES_Individual"
    ),

    OR(

        /* 🔴 Case 1: Wadi Safar RYI → Email Mandatory */
        AND(
            ISPICKVAL(RES_Project__c , "Wadi Safar RYI"),
            ISBLANK(Email)
        ),

        /* 🔴 Case 2: Other Projects → Mobile Mandatory */
        AND(
            NOT(ISPICKVAL(RES_Project__c , "Wadi Safar RYI")),
            ISBLANK(MobilePhone)
        )
    )
)
